#include<bits/stdc++.h>
using namespace std;
bool zi(int a){
	if(a==0||a==1)return false;
	for(int i=2;i<a;i++){
		if(a%i==0){
			return false;
			
		}
	}return true;
}int main(){
	int n,a[101];cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
		
	}for(int i=0;i<n;i++){
		if(zi(a[i])){
			cout<<a[i]<<" ";		
		}
	}
	
}
